                    //  Вызов события об изменении сущности.
                    OnPropertyChanged(_ParentDirectoryPropertyChangedEventArgs);
    
                    //  Установка нового идентификатора.
                    ParentDirectoryId = value.Id;
                }
            }
        }
    }
    
