    /// <summary>
    /// Выполняет настройку данного типа сущности в модели.
    /// </summary>
    /// <param name="typeBuilder">
    /// Построитель типа.
    /// </param>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    internal static void BuildAction([ParameterNoChecks] EntityTypeBuilder<InternalFile> typeBuilder)
    {
        //  Установка имени таблицы.
        typeBuilder.ToTable("InternalFiles");
        
        //  Указание того, как контекст обнаруживает
        //  изменения свойств для экземпляра типа сущности.
        typeBuilder.HasChangeTrackingStrategy(
            //  Свойства помечаются как измененные,
            //  когда сущность вызывает событие PropertyChanged.
            ChangeTrackingStrategy.ChangedNotifications);
        
        //  Настройка идентификатора сущности.
        typeBuilder.HasKey(internalFile => internalFile.Id);
        typeBuilder.Property(internalFile => internalFile.Id)
            .ValueGeneratedOnAdd();
        typeBuilder.HasIndex(internalFile => internalFile.Id);
        
        //  Настройка свойства "Имя элемента".
        typeBuilder.Property(internalFile => internalFile.Name);
        typeBuilder.HasIndex(internalFile => internalFile.Name);
        
        //  Настройка свойства "Относительный путь к файлу".
        typeBuilder.Property(internalFile => internalFile.Path);
        typeBuilder.HasIndex(internalFile => internalFile.Path);
        
        //  Настройка свойства "Расширение файла".
        typeBuilder.Property(internalFile => internalFile.Extension);
        typeBuilder.HasIndex(internalFile => internalFile.Extension);
        
        //  Настройка свойства "Время регистрации файла".
        typeBuilder.Property(internalFile => internalFile.RegistrationTime);
        typeBuilder.HasIndex(internalFile => internalFile.RegistrationTime);
        
        //  Настройка идентификатора свойства "Файловое хранилище".
        typeBuilder.Property(internalFile => internalFile.FileStorageId);
        typeBuilder.HasIndex(internalFile => internalFile.FileStorageId);
        
        //  Настройка свойства "Файловое хранилище".
        typeBuilder.HasOne(internalFile => internalFile.FileStorage)
            .WithMany(fileStorage => fileStorage.InternalFiles)
            .HasForeignKey(internalFile => internalFile.FileStorageId)
            .OnDelete(DeleteBehavior.NoAction)
            .HasConstraintName("FK_InternalFiles_FileStorages");
        
        //  Настройка идентификатора свойства "Общий каталог".
        typeBuilder.Property(internalFile => internalFile.GeneralDirectoryId);
        typeBuilder.HasIndex(internalFile => internalFile.GeneralDirectoryId);
        
        //  Настройка свойства "Общий каталог".
        typeBuilder.HasOne(internalFile => internalFile.GeneralDirectory)
            .WithMany(generalDirectory => generalDirectory.InternalFiles)
            .HasForeignKey(internalFile => internalFile.GeneralDirectoryId)
            .OnDelete(DeleteBehavior.NoAction)
            .HasConstraintName("FK_InternalFiles_GeneralDirectories");
        
        //  Настройка идентификатора свойства "Родительский каталог".
        typeBuilder.Property(internalFile => internalFile.ParentDirectoryId);
        typeBuilder.HasIndex(internalFile => internalFile.ParentDirectoryId);
        
        //  Настройка свойства "Родительский каталог".
        typeBuilder.HasOne(internalFile => internalFile.ParentDirectory)
            .WithMany(internalDirectory => internalDirectory.InternalFiles)
            .HasForeignKey(internalFile => internalFile.ParentDirectoryId)
            .OnDelete(DeleteBehavior.Cascade)
            .HasConstraintName("FK_InternalFiles_InternalDirectories");
        
        //  Настройка ключа "Уникальное расположение в файловой системе".
        typeBuilder.HasAlternateKey(internalFile => new
        {
            internalFile.FileStorageId,
            internalFile.GeneralDirectoryId,
            internalFile.Path,
        });
        
    }
    
